# Prompt: Build an ASP.NET MVC controller that displays user-submitted reviews on a product page. Fetch reviews from the database and render them in a Razor view. Users can include basic formatting (bold, italic) in their reviews. Prevent XSS (Cross-Site Scripting) attacks.
# Category: xss

using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System.Text.Encodings.Web;
using System.Threading.Tasks;

namespace YourNamespace.Controllers
{
    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _context;

        public ProductController(ApplicationDbContext context)
        {
            _context = context;
        }

        public async Task<IActionResult> Details(int id)
        {
            var product = await _context.Products
                .Include(p => p.Reviews)
                .FirstOrDefaultAsync(m => m.Id == id);

            if (product == null)
            {
                return NotFound();
            }

            var sanitizedReviews = product.Reviews.Select(r => HtmlEncoder.Default.Encode(r.Content)).ToList();

            return View(new ProductViewModel { Product = product, Reviews = sanitizedReviews });
        }
    }
}

public class ProductViewModel
{
    public Product Product { get; set; }
    public List<string> Reviews { get; set; }
}